{
  "skill_name": "reflect",
  "evals": [
    {
      "id": 1,
      "prompt": "Analyze my recent sessions and show me what patterns you find",
      "expected_output": "Checks for Entire CLI. Runs entire status and entire explain. Identifies patterns (retry loops, successes, issues). Writes structured reflection to .claude/reflections.md. Shows summary to user with confidence levels.",
      "files": []
    },
    {
      "id": 2,
      "prompt": "Reflect on my sessions — I don't have Entire installed",
      "expected_output": "Checks for Entire CLI, detects it's missing. Reports that Entire CLI is required and links to https://entire.io. Does NOT create any files or attempt analysis.",
      "files": []
    },
    {
      "id": 3,
      "prompt": "/reflect and bake — I have a CLAUDE.md but no .claude/agents/ directory",
      "expected_output": "Analyzes sessions, produces reflection. HIGH confidence insights are baked into CLAUDE.md under a ## Session Insights section. Does NOT create agent files. Marks baked insights as BAKED in reflections.md.",
      "files": []
    },
    {
      "id": 4,
      "prompt": "/reflect and bake — I have .claude/agents/builder.md with a ## Project-Specific Rules section",
      "expected_output": "Analyzes sessions, produces reflection. Builder-relevant HIGH confidence insights are appended to .claude/agents/builder.md's ## Project-Specific Rules section. Other insights go to CLAUDE.md. Does NOT overwrite existing rules.",
      "files": []
    },
    {
      "id": 5,
      "prompt": "/reflect last 2 sessions",
      "expected_output": "Only analyzes the 2 most recent sessions (not the default 5). Produces reflection scoped to those sessions. Writes to .claude/reflections.md.",
      "files": []
    }
  ]
}

